module divider(
    input [7:0] obf_dividend,
    input [7:0] divisor,
    output reg [7:0] quotient,
    output reg [7:0] remainder
);
    always @(*) begin
        if (divisor == 8'b00000000) begin
            quotient = 8'b00000000;
            remainder = obf_dividend;
        end else begin
            quotient = obf_dividend / divisor;
            remainder = obf_dividend % divisor;
        end
    end
endmodule
